      this.totalWaitTime += waitTime;
      this.waitCount++;

      item.execute().then(
        (result) => {
          this.processed++;
          this.running--;
          item.deferred.resolve(result);
          this.processNext();
          this.checkDrain();
        },
        (error) => {
          this.processed++;
