      return { docCount: 0, chunkCount: 0 };
    }

    const files = this.listFiles(corpusDir);
    const allowedExts = [".md", ".txt"];

    let totalChunks = 0;
    for (const file of files) {
      const ext = path.extname(file).toLowerCase();
      if (!allowedExts.includes(ext)) continue;

