      document: s.doc,
      score: s.score,
      source: {
        id: s.chunk.id,
        type: "document" as const,
        name: s.doc.title,
        path: s.doc.path,
        freshness: this.computeDocFreshness(s.doc.metadata.updatedAt),
        timestamp: s.doc.metadata.updatedAt,
        confidence: Math.min(0.95, s.score * 2),
