    prompt,
    width: 1024,
    height: 1024,
    num_inference_steps: 30,
    guidance_scale: 7.5,
    response_format: "png",
  });

  const headers: Record<string, string> = { "Content-Type": "application/json" };
  if (gatewayToken) headers["Authorization"] = `Bearer ${gatewayToken}`;

